import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('Authorization', '')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_data = decoded.decode('utf-8')
        token_obj = json.loads(token_data)
        if token_obj.get('valid'):
            return token_obj.get('data')
        else:
            return None
    except (base64.binascii.Error, json.JSONDecodeError):
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    yaml_data = request.get_data(as_text=True)
    try:
        parsed = yaml.safe_load(yaml_data)
        return jsonify(parsed)
    except yaml.YAMLError as e:
        return jsonify(error=str(e)), 400
    except Exception as e:
        return jsonify(error=str(e)), 500
